// src/api/server.ts
import http from "node:http";

type Handler = (req: http.IncomingMessage, res: http.ServerResponse) => void;

const routes = new Map<string, Handler>();

export function get(path: string, handler: Handler): void {
  routes.set(`GET ${path}`, handler);
}

export function post(path: string, handler: Handler): void {
  routes.set(`POST ${path}`, handler);
}

export function createServer(): http.Server {
  return http.createServer((req, res) => {
    const key = `${req.method} ${req.url}`;
    const handler = routes.get(key);
    if (!handler) {
      res.statusCode = 404;
      res.end("not found");
      return;
    }
    handler(req, res);
  });
}

// Existing endpoints — high-traffic, currently unprotected against abuse.
get("/api/health", (_req, res) => res.end("ok"));
post("/api/login", (_req, res) => res.end("{}"));
post("/api/search", (_req, res) => res.end("[]"));

// prototype/SettingsPanel.jsx  (working reference — PORT this shell, do not re-derive)
import { useState } from "react";
import { Button } from "../src/ui/Button";
import { saveSettings } from "../src/api/settings";

// Single parent holds ALL settings state (constraint: one controlled component).
export function SettingsPanel({ initial }) {
  const [tab, setTab] = useState("profile");
  const [form, setForm] = useState(initial);
  const set = (k) => (v) => setForm((f) => ({ ...f, [k]: v }));

  return (
    <div className="settings">
      <nav>
        {["profile", "notifications", "danger"].map((t) => (
          <Button key={t} variant={t === tab ? "active" : "ghost"} onClick={() => setTab(t)}>
            {t}
          </Button>
        ))}
      </nav>
      {tab === "profile" && (
        <ProfileSection value={form.profile} onChange={set("profile")} />
      )}
      {tab === "notifications" && (
        <NotificationsSection value={form.notifications} onChange={set("notifications")} />
      )}
      {tab === "danger" && <DangerZone onDelete={form.onDelete} />}
      <Button variant="primary" onClick={() => saveSettings(form)}>Save</Button>
    </div>
  );
}

